-- Seed Philippine LGU and barangay reference data from PSGC.
--
-- Source: Philippine Statistics Authority, Philippine Standard Geographic Code as of 31 March 2026.
-- Reference: https://psa.gov.ph/classification/psgc/
-- Data acquisition: static JSON dump generated from PSGC data at https://barangays.sanchez.ph/downloads/all.json.
-- 1Q 2026 PSA release corrections applied here:
-- - Retired Barangay San Rafael, City of Calaca, Batangas (merged with Dacanlao).
-- - Corrected Sanchez Mira, Genitligan, Ambuklao, Daklan, Sto. Rosario, Sto. Ni?o, and St. Peter names.
--
-- Creates/updates:
-- - 1642 LGUs
-- - 42010 barangays
--
-- IDs use psgc_* prefixes and are safe to re-run without deleting user-created rows.

BEGIN;

DELETE FROM "barangays" WHERE "id" LIKE 'psgc_brgy_%';
DELETE FROM "lgus" WHERE "id" LIKE 'psgc_lgu_%';


























































































COMMIT;
